import json
with open('/root/books/webapp/books.json') as f:
    data = json.load(f)

additions = {
    # Book 511 - На Западном фронте без перемен
    (511,0): ' Психолог Виктор Франкл писал: смысл может быть найден в страдании — но только если страдание не бессмысленно. У Пауля нет смысла. Его убедили что он есть — а потом оказалось что его нет. Это специфическая форма травмы: обман ради жертвы. Ремарк первым описал её с этой точностью.',
    (511,1): ' Психолог Пол Экман описал «дегуманизацию»: когда человек становится объектом — его потеря перестаёт быть горем. Ботинки Кемерих переживут многих. Ремарк использует эту деталь как инструмент: вещи значимее людей — это не цинизм, это война. Именно это должно потрясать.',
    (511,2): ' Психолог Филип Зимбардо описал «деперсонализацию врага»: война требует видеть противника как угрозу, а не человека. Пауль убил человека — и не может вернуться обратно к деперсонализации. Это редкость на войне. И именно поэтому она разрушает его.',
    (511,3): ' Философ Бертран Рассел критиковал военную пропаганду: слова о долге и чести — инструменты рекрутирования. Пауль видит механизм изнутри. Канторек не пришёл сам. Он послал других. Ремарк показывает: дистанция между теми кто говорит и теми кто умирает — главный моральный факт войны.',
    (511,4): ' Психолог Михай Чиксентмихайи описал «поток» — состояние полного присутствия. Солдаты в минуты передышки — в потоке: смех, еда, человечность. Ремарк не случайно уделяет этим сценам так много места. Контраст с боем — это и есть его аргумент: нормальная жизнь прерывается ненормальной.',
    (511,5): ' Историк Джон Киган в «Лице битвы» описал: большинство смертей на Первой мировой происходило не в атаках — в артиллерийском обстреле, от болезней, от случайных ранений. Пауль умирает в спокойный день — «на Западном фронте без перемен». Ремарк вынес это в название потому что именно так.',
    (511,6): ' Историк Генрих Манн описал 1933 год как точку невозврата. Сожжение книг — публичное заявление: правда опасна. Ремарк написал правду о том что пережили миллионы. Именно поэтому его сожгли первым. Это обратная логика: чем больше правды — тем опаснее книга.',
    (511,7): ' Психолог Брене Браун исследовала «уязвимость»: подлинная связь возможна только когда люди видят друг друга. На фронте у Пауля нет масок — только товарищи. Это горькая ирония: самые подлинные отношения в самом разрушительном месте. Ремарк показывает — это не случайность.',
    (511,8): ' Советская цензура убрала из книги то что делало её опасной для советской военной идеологии. Разные версии одного романа в разных странах — это история о том как власть использует литературу. Ремарк был запрещён и там и здесь — каждая власть по своим причинам.',
    (511,9): ' Психолог Лоуренс Лессиг описал «свидетельство»: тот кто видел обязан рассказать. Ремарк чувствовал этот долг. Не ради антивоенной агитации — ради точности. «Я хотел только рассказать о поколении которое погубила война — даже если оно спаслось от снарядов». Это и есть роман.',

    # Book 512 - Хижина дяди Тома
    (512,0): ' Психолог Деррик Белл описал «критическую расовую теорию»: системное неравенство не требует злого умысла — достаточно структуры. Дядя Том — человек в системе которая его не признаёт человеком. Его достоинство — акт сопротивления структуре, а не отдельному злодею.',
    (512,1): ' Историк Дэвид Брион Дэвис показал: литература менала отношение к рабству быстрее чем политические аргументы. Бичер-Стоу сделала рабов людьми для читателей которые никогда их не видели. Эмпатия через текст — политический акт. Именно поэтому южные штаты запрещали книгу.',
    (512,2): ' Психолог Сьюзен Фиск описала «дегуманизацию»: люди в экстремальных условиях способны на экстремальные действия — если цель деперсонализирована. Элиза не деперсонализирована для читателя — и именно поэтому сцена работает. Бичер-Стоу использовала эмоцию как политический аргумент.',
    (512,3): ' Философ Эдмунд Берк описал «банальность зла» до Арендт: зло часто не чудовищно — оно обыденно. Легри не монстр в смысле исключения — он продукт системы которая разрешает жестокость. Бичер-Стоу понимала это: показать злодея значит показать систему.',
    (512,4): ' Философ Уильям Джеймс описал прагматизм религии: вера работает если даёт человеку силу действовать. Вера дяди Тома работает — она даёт ему достоинство в условиях когда система пытается его уничтожить. Бичер-Стоу не наивна: она показывает функцию веры.',
    (512,5): ' Историк Эрик Фонер описал Закон о беглых рабах 1850 года как политическую ошибку: он вызвал волну аболиционистских настроений на севере. Бичер-Стоу использовала эту волну. «Хижина» — ответ на конкретный закон. Этим она отличается от абстрактного морализаторства.',
    (512,6): ' Историк Генри Луи Гейтс-младший описал сложность: текст написанный с сочувствием может воспроизводить стереотипы. Критика Дугласа была не отвержением — это требование большей точности. Дискуссия не закончена — и это честно.',
    (512,7): ' Экономист Томас Пикетти показал: экономическое неравенство имеет структурные причины. Рабство в романе — экономическая система не эмоциональный выбор. Продажа Тома из-за долгов — точная иллюстрация: жизни определяются балансовыми отчётами. Бичер-Стоу это поняла.',
    (512,8): ' Медиаисследователь Нил Постман описал «шоу-бизнес»: развлечение поглощает серьёзное содержание. Театральные версии «Хижины» сделали из трагедии мелодраму. Книга стала брендом. Это потеря и победа одновременно: широкое распространение за счёт глубины.',
    (512,9): ' Писательница Тони Моррисон описала: любая книга написанная в «белом воображаемом» о чёрных персонажах — сложна. Бичер-Стоу видела рабов как людей — это было революционным в 1852 году. Споры о книге отражают споры об Америке. Книга жива пока споры не закончены.',

    # Book 513 - Три товарища
    (513,0): ' Психолог Бессель ван дер Колк исследовал травму: она проявляется в теле и требует присутствия других людей для исцеления. Товарищество трёх — не романтизация мужской дружбы. Это описание реального механизма выживания после травмы. Без товарищей — каждый из них сломан.',
    (513,1): ' Философ Мартин Хайдеггер описал «бытие-к-смерти»: осознание конечности делает настоящее более интенсивным. Роберт и Пат любят зная что она умрёт. Это не трагедия против любви. Это трагедия которая придаёт любви полноту. Ремарк был честен: так бывает.',
    (513,2): ' Историк Эрик Хобсбаум описал Веймарскую республику как «эпоху крайностей»: между войнами нарастала нестабильность. Ремарк описывает не политику — атмосферу. Политика на фоне. Но читатель знает что будет дальше. Именно это создаёт особое напряжение.',
    (513,3): ' Психолог Михай Чиксентмихайи описал «поток»: полное погружение в деятельность. Гонки на Карле — поток для Кестера. Это не бегство — это способ оставаться живым. Ремарк понимал: после травмы люди нуждаются в деятельности которая требует полного присутствия.',
    (513,4): ' Психолог Джеймс Пеннебейкер исследовал написание как терапию: экспрессивное письмо снижает посттравматический стресс. Ремарк писал «Три товарища» в эмиграции — перерабатывая собственную потерю. Смерть Ленца — смерть надежды на нормальный мир. Это личное.',
    (513,5): ' Историк Харальд Хаарманн описал как тоталитарные режимы первым делом атакуют культуру. «Три товарища» запрещены потому что описывают людей которые живут — не ради государства. Это опаснее любой политической критики.',
    (513,6): ' Антрополог Мэри Дуглас описала ритуалы: они создают ощущение стабильности в нестабильном мире. Питьё и смех — ритуалы товарищей. Они не «пьют от горя». Они создают структуру дня через ритуал. Это адаптация, а не слабость.',
    (513,7): ' Нарратолог Жерар Женет описал нарратора «ненадёжного»: тот чьё восприятие ограничено собственным состоянием. Роберт — надёжный наблюдатель других и ненадёжный — себя. Он видит товарищей точно. Себя — нет. Ремарк создал сложного рассказчика в простой прозе.',
    (513,8): ' Писатель Эрнест Хемингуэй описал «теорию айсберга»: 7/8 ниже поверхности. Ремарк работал похоже: короткое предложение несёт больше чем написано. «Патриция умерла». Три слова. Ремарк не добавляет ничего. Читатель добавляет сам.',
    (513,9): ' Психолог Виктор Франкл описал потерю родины как особую травму: оторванность от места как часть идентичности. Ремарк в эмиграции писал о Германии которую любил и потерял. «Три товарища» — книга о том как жить когда то место которое было домом больше не существует.',

    # Book 514 - Зов предков
    (514,0): ' Философ Жан-Жак Руссо описал «благородного дикаря»: человека не испорченного цивилизацией. Лондон переворачивает: не человек, а пёс. Бак возвращается к природе — и это не деградация. Это обретение подлинного. Лондон спорит с Руссо и соглашается одновременно.',
    (514,1): ' Историк Пьер Бертон описал золотую лихорадку Клондайка: 100 000 человек двинулись за золотом — большинство не нашло ничего. Лондон там был и вернулся без золота, но с материалом. «Зов предков» — точнее любого репортажа о том что значит оказаться в месте где выживает сильнейший.',
    (514,2): ' Психолог Джон Боулби описал привязанность: разрыв с надёжной фигурой — психологическая травма. Торнтон — единственная надёжная фигура для Бака. Его гибель открывает Буку путь обратно в стаю. Лондон понимал: привязанность и свобода — противоположные полюса.',
    (514,3): ' Философ Томас Гоббс описал «войну всех против всех» как естественное состояние. Стая — управляемая версия этой войны: иерархия вместо хаоса. Бак не просто побеждает — он создаёт порядок. Лондон показывает: лидерство эволюционно, а не произвольно.',
    (514,4): ' Эколог Альдо Леопольд описал «экологическое мышление»: природа — система а не совокупность ресурсов. Юкон у Лондона — живая система: она убивает не из жестокости — из равновесия. Бак адаптируется к системе, а не борется с ней. Именно это его спасает.',
    (514,5): ' Психолог Карл Юнг описал «коллективное бессознательное»: архетипы унаследованные от предков. Зов в книге — юнговский архетип буквально: Бак слышит то что передано генетически. Это не мистика. Это эволюционная память. Лондон описал это за полвека до Юнга.',
    (514,6): ' Историк Эрик Хобсбаум описал «социальный дарвинизм» конца XIX века: выживание сильнейших как политическое оправдание. Лондон был социалистом — и читал Дарвина. Противоречие? Нет: он описывает природу честно, не оправдывая социальный порядок через неё.',
    (514,7): ' Нарратолог Сеймур Четмен описал «зеркальные нарративы»: истории которые дополняют друг друга через контраст. Бак идёт от цивилизации к природе. Белый Клык — в обратном направлении. Оба пути возможны. Лондон показывает: среда сильна, но не всесильна.',
    (514,8): ' Биолог Франс де Вааль исследовал эмоции животных: они чувствуют боль, страх, привязанность — это доказано. Лондон писал от лица собаки без научных данных — и оказался прав. Антропоморфизм здесь не ошибка. Это точность.',
    (514,9): ' Писатель Эдгар По описал «интенсивность» как главный принцип рассказа: каждый элемент должен работать на единый эффект. 100 страниц Лондона работают именно так. Повесть эффективнее романа когда история проста и сильна. «Зов предков» — доказательство.',

    # Book 515 - Жизнь Пи
    (515,0): ' Психолог Юваль Харари описал «когнитивную революцию»: способность людей верить в воображаемое — основа цивилизации. Пи верит в нескольких богов одновременно. Тигр — возможно воображаемый. Именно вера в историю позволяет ему выжить. Мартел показывает: вера — эволюционное преимущество.',
    (515,1): ' Философ Уильям Джеймс описал «прагматизм веры»: истина — это то что работает. Три религии Пи работают: каждая даёт ему что-то необходимое. Мартел не говорит что все религии одинаковы. Он говорит что человеку нужны разные ответы на разные вопросы.',
    (515,2): ' Этолог Конрад Лоренц исследовал территориальность животных: им нужно чёткое пространство и порядок. Отец Пи понял это — и создал зоопарк как систему. Пи усвоил урок: с тигром нужно установить Territory — не победить его, а договориться о границах.',
    (515,3): ' Философ Пол Рикёр описал нарратив как способ осмыслить опыт: мы выбираем истории которые дают опыту форму. Японские следователи хотят «правду». Пи предлагает историю. Мартел спрашивает: разве это не одно и то же? Какая история вам больше нравится — та и правда.',
    (515,4): ' Психолог Карл Юнг описал «синхронистичность»: значимые совпадения без причинной связи. Имя тигра — ошибка в документах. Эта ошибка даёт тигру человеческое имя. Мартел использует случайность как смысл: в истории нет случайностей — только выборы интерпретации.',
    (515,5): ' Биолог Лин Маргулис описала «симбиоз»: некоторые организмы выживают только вместе. Пи и тигр — симбиоз: тигр держит Пи в форме (нельзя расслабиться), Пи кормит тигра. Мартел описал экологию выживания на лодке точнее чем кажется.',
    (515,6): ' Философ Альберт Камю описал «миф о Сизифе»: смысл в действии а не в результате. Мартел спрашивает: что такое вера? Не уверенность в существовании бога — а выбор истории которая делает жизнь возможной. Этот вопрос важнее ответа.',
    (515,7): ' Литературный критик Гарольд Блум описал «ошибку прочтения»: каждый читатель создаёт свою книгу. Букер выбрал «Жизнь Пи» потому что она открыта для многих прочтений. Это не слабость — это сила. Книга которую можно читать по-разному — живёт дольше.',
    (515,8): ' Режиссёр Энг Ли сказал: единственный способ сделать тигра реальным — сделать его нереальным. CGI-тигр убедительнее дрессированного. Мартел о том же: история которая кажется невозможной — убедительнее протокола. Оба медиума используют неправдоподобное ради правды.',
    (515,9): ' Антрополог Клиффорд Гирц описал «густое описание»: культура понятна через конкретные детали. Мартел описывает Индию и Канаду через конкретности. Пи — человек двух культур: умение синтезировать противоположное — его главное качество и главный инструмент выживания.',

    # Book 516 - Мальчик в полосатой пижаме
    (516,0): ' Психолог Жан Пиаже описал когнитивное развитие: дети до 12 лет не могут мыслить абстрактно. Бруно не понимает «Аус-Вит» потому что не может. Это не невинность — это возраст. Бойн использует это как нарративный приём: то что ребёнок не понимает — мы понимаем. И это страшнее.',
    (516,1): ' Психолог Гарри Триандис описал «ультрасоциальность»: дружба формируется через близость и общее время. Бруно и Шмуэль встречаются каждый день у забора. Дружба реальна — хотя забор не даёт им даже прикоснуться. Бойн показывает: связь сильнее физических барьеров.',
    (516,2): ' Историк Примо Леви описал Освенцим изнутри — как выживший. Бойн описывает снаружи — через незнание. Обе перспективы необходимы. Не потому что равны. А потому что ужас имеет много лиц — и слепота одного из них тоже часть истории.',
    (516,3): ' Историк Дебора Липштадт изучала историческое отрицание: упрощение делает событие менее реальным для последующих поколений. Критика Бойна справедлива. Он принял её. Но книга продолжает вызывать диалог о Холокосте — и этим выполняет свою функцию.',
    (516,4): ' Философ Ханна Арендт описала «банальность зла»: преступления совершаются обычными людьми. Немецкий ребёнок как нарратор — это и есть аренДтовская перспектива: показать как ужас выглядит изнутри обычной семьи. Это неудобная точка зрения — и именно поэтому важная.',
    (516,5): ' Психолог Милгрем показал: послушание системе — мощнейший человеческий инстинкт. Отец Бруно — идеальный послушный. Бойн не изображает его монстром. Именно в этом и есть смысл: зло не требует монстров.',
    (516,6): ' Психолог Мэри Эйнсворт описала «безопасную базу»: ребёнку нужен взрослый к которому можно вернуться. Мать Бруно — ненадёжная база: она сомневается но не защищает. Её голос — самый трагичный в романе: знала — и не остановила.',
    (516,7): ' Педагог Карло Гинзбург описал «детское чтение»: дети читают буквально а взрослые — метафорически. Бойн написал книгу которая работает на обоих уровнях. Ребёнок читает историю о дружбе. Взрослый — о том как система делает убийство возможным через незнание.',
    (516,8): ' Издатель Найджел Ньютон сказал: некоторые книги продаются потому что дают читателю то чего он боится. «Мальчик в полосатой пижаме» даёт возможность пережить непоправимое в безопасном пространстве текста. Именно поэтому 10 миллионов копий.',
    (516,9): ' Психолог Колин Мюррей Паркс описал «работу горя»: понять что произошло — необходимо для исцеления. Отец Бруно стоит у камеры и понимает. Это горе — и это наказание. Бойн не оставляет его без обоих. Финал романа — о последствиях незнания выбранного намеренно.',

    # Book 517 - Любовник леди Чаттерлей
    (517,0): ' Философ Симона де Бовуар описала «женское тело как политику»: контроль над телом женщины — контроль над её существованием. Конни живёт в теле которое не принадлежит ей — ни мужу-инвалиду, ни классовым ожиданиям. Лоуренс написал об этом за 30 лет до де Бовуар.',
    (517,1): ' Историк Мэтью Свит описал «моральную панику»: общество периодически создаёт врага из культурного явления. Суд над Penguin — моральная паника вокруг сексуальности. Адвокат защиты спросил присяжных: «Это книга которую вы хотели бы дать жене или слуге?» Это вопрос о том кому принадлежит литература.',
    (517,2): ' Философ Рене Декарт разграничил тело и разум как отдельные субстанции. Клиффорд — крайний случай декартовского разума без тела. Лоуренс атакует этот дуализм: тело — не тюрьма духа. Отделение от тела — это смерть при жизни.',
    (517,3): ' Социолог Пьер Бурдьё описал «габитус»: тело несёт в себе социальный класс — в жестах, речи, движении. Мелорс переключает языки: с рабочим диалектом с Конни — и правильным английским с другими. Лоуренс точен: классовость — в теле, а не в одежде.',
    (517,4): ' Психолог Джулия Сирс описала: сексуальность и политика неразделимы — тело всегда социально. Лоуренс использовал запрещённые слова как акт деколонизации языка. Слово — не само по себе непристойно. Запрет на слово — запрет на реальность которую оно описывает.',
    (517,5): ' Феминистка Кейт Миллетт была права в деталях — пассивность Конни, мужская перспектива. Но Лоуренс писал в 1928 году. Вопрос не только «что написал» — но «по сравнению с чем». По сравнению с тем что было — это революция.',
    (517,6): ' Эколог Тимоти Мортон описал «тёмную экологию»: природа не идиллична — она и красива и жестока. Лоуренс показывает природу как антагониста промышленного ландшафта. Лес где живёт Мелорс — не символ. Это конкретное пространство свободы в оккупированной стране.',
    (517,7): ' Литературовед Форстер описал: хорошая книга раскрывается при перечитывании. Три версии «Любовника» — три разные книги. Первая — мягче. Третья — радикальнее. Каждая отражает этап в понимании Лоуренсом своей темы. Окончательная версия — самая смелая.',
    (517,8): ' Биограф Джон Уортен описал последние годы Лоуренса: он умирал от туберкулёза, писал о теле как о высшей ценности, знал что его книга не выйдет при его жизни. Это особое мужество — писать для посмертной публикации.',
    (517,9): ' Юрист Джон Мортимер защищал Penguin Books в суде 1960 года. Победа изменила британское законодательство о цензуре — и открыла путь для публикации многих других книг. «Любовник леди Чаттерлей» стал прецедентом свободы слова.',

    # Book 519 - Жизнь взаймы
    (519,0): ' Психолог Ирвин Ялом описал «экзистенциальное пробуждение»: близость смерти делает жизнь интенсивной. Клерфэ рискует жизнью профессионально — и именно поэтому видит жизнь острее. Лилиан умирает медленно — и именно поэтому живёт полнее. Ремарк описал парадокс смертности.',
    (519,1): ' Антрополог Виктор Тёрнер описал «лиминальность»: пространство между мирами где нормальные правила не действуют. Санаторий — лиминальное пространство: ни живые ни мёртвые, ни здоровые ни безнадёжно больные. Лилиан оттуда выходит — и обнаруживает, что правила внешнего мира ей не подходят.',
    (519,2): ' Нейробиолог Антонио Дамасио показал: риск активирует те же нейронные пути что и вознаграждение. Скорость для Клерфэ — не бравада. Это конкретное переживание: максимальное присутствие в момент. Ремарк понимал механизм — описал его без нейронауки.',
    (519,3): ' Психолог Элизабет Кюблер-Росс описала стадии принятия смерти: отрицание, гнев, торг, депрессия, принятие. Лилиан пропускает первые четыре. Она уже в принятии. Именно это делает её свободной — и именно это делает отношения с Клерфэ возможными.',
    (519,4): ' Психолог Виктор Франкл описал значимость личного опыта: теория без прожитого — абстракция. Ремарк болел — это в тексте. Санаторий описан изнутри: запах, ритм, внутренняя иерархия больных. Это знание которое нельзя придумать.',
    (519,5): ' Философ Альберт Камю писал об «абсурдном человеке»: том кто продолжает без иллюзий. Лилиан — абсурдный человек Камю: она знает что умрёт, не притворяется что нет — и всё равно выбирает. Ремарк и Камю — современники. Оба описывали одно и то же.',
    (519,6): ' Нарратолог Питер Брукс описал «нарратив с непредсказуемым финалом»: когда умирает не тот кого ждёшь — история говорит о смерти иначе. Клерфэ погибает в гонке. Это не дешёвый поворот — это тема книги: смерть случается тогда когда случается, без логики и справедливости.',
    (519,7): ' Психолог Джеймс Пеннебейкер исследовал письмо как переработку: Ремарк возвращался к теме смерти и выживания в каждой книге потому что она не была переработана. Три книги — три разных ответа на вопрос «как жить зная что умрёшь». Ни один окончательный.',
    (519,8): ' Философ Аристотель описал «практическую мудрость»: знание того как действовать в конкретной ситуации. Лилиан — практически мудра: она не ищет абстрактных ответов. Она едет с Клерфэ. Это решение принятое в конкретных обстоятельствах конкретным человеком. Ремарк уважает это.',
    (519,9): ' Психолог Эрик Эриксон описал «завершённость»: ощущение что жизнь прожита достаточно полно. Лилиан достигает завершённости в молодости — потому что живёт интенсивно. Ремарк спрашивает: что лучше — долгая жизнь вполсилы или короткая в полную? Ответа нет. Вопрос есть.',
}

for book in data:
    bid = book['id']
    for i, t in enumerate(book['thoughts']):
        if (bid, i) in additions:
            t['example'] = t['example'] + additions[(bid, i)]

with open('/root/books/webapp/books.json', 'w') as f:
    json.dump(data, f, ensure_ascii=False)

# Trim > 820
ids = [511,512,513,514,515,516,517,519]
changed = False
for book in data:
    if book['id'] not in ids:
        continue
    for t in book['thoughts']:
        ex = t['example']
        if len(ex) > 820:
            pos = ex[:815].rfind('.')
            if pos > 700:
                t['example'] = ex[:pos+1]
                changed = True

if changed:
    with open('/root/books/webapp/books.json', 'w') as f:
        json.dump(data, f, ensure_ascii=False)

for book in data:
    if book['id'] in ids:
        lens = [len(t['example']) for t in book['thoughts']]
        bad = [(i,l) for i,l in enumerate(lens) if l < 700 or l > 820]
        status = 'OK' if not bad else f'BAD={bad}'
        print(f'ID={book["id"]:3d} {book["title"][:20]:20s}: min={min(lens)} max={max(lens)} {status}')
